using Forge.Core.Entities;
using Forge.Core.Enums;
using Forge.Data.Context;

using Serilog;

namespace Forge.Api.Data.TrainingContent;

public class ComplianceTraining : TrainingContentBase
{
    public ComplianceTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Compliance Forms Overview",
            Slug = "compliance-forms-overview",
            Summary = "What compliance forms are, which forms QB Engineer supports (W-4, I-9, state withholding, direct deposit, workers' comp, handbook), when forms need updating, and how they connect to payroll and onboarding.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/account/tax-forms"]""",
            Tags = """["compliance","tax-forms","w-4","i-9","onboarding"]""",
            ContentJson = """{"body":"## Compliance Forms Overview\n\nThe Employee Compliance Forms module manages the tax withholding, employment eligibility, and policy acknowledgment forms that every employee must complete. These are government-mandated and company-required documents that feed directly into payroll processing, employment verification, and regulatory compliance.\n\n### What Forms Does QB Engineer Support?\n\nQB Engineer handles six categories of compliance forms, each tracked as a ComplianceFormTemplate:\n\n- **W-4 (Employee's Withholding Certificate)** — The IRS form that determines how much federal income tax is withheld from your paycheck. You choose your filing status (Single, Married Filing Jointly, Head of Household), indicate whether you hold multiple jobs, claim dependents, and specify any additional withholding or exemptions.\n\n- **I-9 (Employment Eligibility Verification)** — The USCIS form that verifies your identity and authorization to work in the United States. It has two sections: Section 1 (completed by the employee — citizenship status, personal info, signature) and Section 2 (completed by the employer — document verification within 3 business days of the employee's start date). The I-9 requires supporting identity documents from List A (identity + work authorization) OR List B (identity) + List C (work authorization).\n\n- **State Withholding** — Your state-specific income tax withholding form. QB Engineer automatically determines which form you need based on your work location. Some states (like Texas, Florida, Nevada) have no income tax and require no form. Others use the federal W-4 as their withholding basis. States with their own forms (like California, New York, Idaho) have custom form definitions extracted and rendered electronically.\n\n- **Direct Deposit** — Banking information for electronic payroll deposits. Records your bank name, account type (checking/savings), routing number, and account number. Sensitive fields are masked after submission (only last 4 digits shown).\n\n- **Workers' Compensation Acknowledgment** — Company policy acknowledgment for workplace injury procedures and reporting requirements.\n\n- **Employee Handbook Acknowledgment** — Confirmation that you have received, read, and agree to abide by the company's employee handbook.\n\n### The Onboarding Wizard\n\nAll six form types are integrated into the unified onboarding wizard at /onboarding. New employees complete all required forms in a single guided workflow rather than navigating to each form individually. The Tax Forms page (Account > Tax Forms) shows a banner linking to the onboarding wizard when forms are incomplete.\n\nAfter onboarding is complete, employees can return to Account > Tax Forms to review their submissions, download signed PDFs, or update forms when their tax situation changes.\n\n### When Do Forms Need Updating?\n\n- **W-4**: Any time your tax situation changes — marriage, divorce, new dependents, second job, or significant income changes. There is no annual requirement, but reviewing annually is recommended.\n- **I-9**: Cannot be changed after submission per federal regulations. Contact HR for corrections. Reverification is required when work authorization documents expire.\n- **State Withholding**: When your tax situation changes or when you move to a different state (your work location determines which state form applies).\n- **Direct Deposit**: Contact payroll to update banking information.\n- **Workers' Comp / Handbook**: Typically acknowledged once during onboarding. May require re-acknowledgment if policies are updated.\n\n### How Forms Connect to Payroll\n\nCompliance form data drives payroll calculations:\n- W-4 filing status and withholding elections determine federal tax withholding amounts\n- State withholding elections determine state tax withholding\n- Direct deposit information routes payroll payments to the correct bank account\n- Completed forms are tracked via profile completion keys that gate job assignment — employees with BlocksJobAssignment forms incomplete cannot be assigned to production jobs\n\n### Form Lifecycle\n\nEach form follows a consistent lifecycle:\n1. **Template** — Admin configures the form template (source URL, form definition, DocuSeal integration)\n2. **Submission Created** — Employee starts the form (status: Pending)\n3. **Draft Saved** — Employee can save progress and return later\n4. **Submitted** — Form data validated against required fields and submitted\n5. **Signed** — For forms with DocuSeal integration, a fill-and-sign ceremony produces a legally signed PDF\n6. **Completed** — Profile completion key updated, form marked complete\n\n### Electronic Form Rendering\n\nQB Engineer renders government forms electronically using a metadata-driven compliance form renderer. The system extracts form definitions from official government PDFs (using pdf.js + AI verification), producing JSON layouts that match the original paper form's structure — including step sections, filing status radio groups, amount lines, signature blocks, and worksheets. This means employees fill out the actual W-4 or I-9 layout digitally, not a simplified approximation.\n\n### DocuSeal Integration\n\nForms requiring legally binding signatures use DocuSeal for digital signing. The flow is: collect form data electronically → fill the official government PDF with the collected data (AcroForm field mapping) → send the pre-filled PDF to DocuSeal for e-signature → store the signed PDF in MinIO. This produces a legally compliant signed document that matches what would have been filed on paper.","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Compliance Forms — Guided Tour",
            Slug = "compliance-forms-walkthrough",
            Summary = "A guided tour of the Account > Tax Forms page: form list, completion status, onboarding wizard link, form detail view, electronic form renderer, identity documents, and signing ceremony.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/account/tax-forms"]""",
            Tags = """["compliance","walkthrough"]""",
            ContentJson = """{"appRoute":"/account/tax-forms","startButtonLabel":"Tour Compliance Forms","steps":[{"element":".account-page","popover":{"title":"Form Card","description":"Each compliance form appears as a card showing the form name, description, and current status. A green check_circle icon means the form is complete, with the completion date shown on the right. Incomplete forms show the original form icon. Forms that block job assignment display an amber 'Required' badge.","side":"bottom"}},{"element":".account-page__title","popover":{"title":"Completion Indicator","description":"The icon changes based on status: the form's original icon (e.g., description, account_balance) when incomplete, or a green check_circle when completed. This gives you an instant visual overview of your compliance status.","side":"right"}},{"element":".tax-forms__intro","popover":{"title":"Navigate to Form Detail","description":"Click anywhere on the form card to navigate to the form detail page. For forms handled by the onboarding wizard (W-4, I-9, state withholding, direct deposit, workers' comp, handbook), clicking navigates to /onboarding if the form is incomplete, or to the form detail view if already completed.","side":"left"}},{"element":".account-page","popover":{"title":"Completed Form","description":"Completed forms show a green left border, the check_circle icon, and the completion date. Click to view your submission summary, download the signed PDF, or update the form (where allowed — I-9 forms cannot be changed after submission).","side":"bottom"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Compliance Forms Field Reference",
            Slug = "compliance-forms-field-reference",
            Summary = "Complete reference for every field, button, status, validation rule, and action in the Compliance Forms module — including form list, submission statuses, form actions, submission history, identity documents, and validation rules.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/account/tax-forms"]""",
            Tags = """["compliance","reference"]""",
            ContentJson = """{"title":"Compliance Forms Field Reference","groups":[{"heading":"Form List Fields","items":[{"label":"Form Icon","value":"Material icon identifying the form type. Changes to green check_circle when the form is completed. Icons vary by form: description (W-4), badge (I-9), account_balance (state withholding), account_balance_wallet (direct deposit), health_and_safety (workers' comp), menu_book (handbook)."},{"label":"Form Name","value":"The official name of the compliance form (e.g., 'W-4 Employee's Withholding Certificate', 'I-9 Employment Eligibility Verification'). Displayed as the card title."},{"label":"Description","value":"Brief explanation of the form's purpose. Shown below the form name in smaller text."},{"label":"Completion Date","value":"Displayed on the right side of completed forms in MM/dd/yyyy format. Shows when the form was last submitted and signed."},{"label":"Required Badge","value":"Amber 'Required' text shown on forms where blocksJobAssignment is true. These forms must be completed before the employee can be assigned to production jobs."},{"label":"Onboarding Badge","value":"Teal 'Completed in onboarding wizard' badge shown on incomplete wizard-managed forms (W-4, I-9, state withholding, direct deposit, workers' comp, handbook). Indicates the form should be completed via the onboarding wizard rather than individually."},{"label":"Chevron Icon","value":"Right-pointing chevron_right icon on each form card. Indicates the card is clickable and navigates to the form detail page."}]},{"heading":"Form Submission Statuses","items":[{"label":"Pending","value":"Submission created but not yet completed. The employee has started the form but has not submitted it. May have saved draft data. DocuSeal signing ceremony may be in progress."},{"label":"Opened","value":"The DocuSeal signing link has been opened by the employee. The form data has been collected and the PDF is being signed. Intermediate state between Pending and Completed."},{"label":"Completed","value":"Form has been fully submitted and signed. Profile completion key has been updated. Signed PDF is available for download. For I-9: both Section 1 (employee) and Section 2 (employer) are done."},{"label":"Expired","value":"The submission has expired, typically because a DocuSeal signing link was not completed within the allowed time window. The employee needs to start a new submission."},{"label":"Declined","value":"The DocuSeal signing was declined by the signer. The employee needs to start a new submission or contact HR."}]},{"heading":"Form Actions and Buttons","items":[{"label":"Onboarding Wizard Banner","value":"Teal banner at the top of the Tax Forms list page. Links to /onboarding. Shown only when onboarding status is not allComplete. Contains assignment_ind icon and arrow_forward navigation hint."},{"label":"Back Button","value":"Arrow_back button at the top of the form detail page. Returns to the Tax Forms list. Also appears as the left action in the form renderer footer."},{"label":"Save Draft","value":"Save icon button in the form renderer footer. Saves the current form data as a draft without submitting. The employee can return later to continue filling out the form. Disabled while save is in progress (shows spinning sync icon)."},{"label":"Submit Form","value":"Primary action button with check icon in the form renderer footer. Validates all required fields against the form definition, then submits the form data. For fill-and-sign forms, this triggers the PDF fill + DocuSeal signing ceremony. Disabled when the form is invalid or submission is in progress."},{"label":"Start E-Sign","value":"Primary button with draw icon. Shown for forms with DocuSeal integration that have not yet been started. Creates a new submission and initiates the signing ceremony."},{"label":"Download PDF","value":"Download icon button shown on completed forms. Downloads the signed PDF copy of the submitted form. Disabled while download is in progress (shows spinning sync icon)."},{"label":"Update","value":"Primary edit icon button shown on completed forms that allow resubmission. Opens the form in edit mode for the employee to update their information. Not shown for I-9 forms (which cannot be changed after submission per federal law)."},{"label":"Acknowledge & Complete","value":"Primary check icon button for forms without DocuSeal integration or electronic form definitions (simple acknowledgment forms like workers' comp and handbook). Marks the form as completed."},{"label":"Supporting Identity Documents","value":"Button with folder_open icon, shown only for I-9 forms (requiresIdentityDocs = true). Opens a dialog for uploading List A, List B, and List C identity documents. Badge shows count of uploaded documents."},{"label":"Prev / Next","value":"Navigation buttons in the form renderer footer for multi-page forms. Shows current page number (e.g., '1 / 2'). Prev is disabled on the first page, Next on the last page."}]},{"heading":"Submission History","items":[{"label":"Status Banner (Complete)","value":"Green banner with check_circle icon showing 'Completed MM/dd/yyyy'. Displayed at the top of the form detail when the form is complete."},{"label":"Status Banner (Pending)","value":"Yellow banner with pending icon showing the submission status and start date (e.g., 'Pending — Started 03/15/2026'). Displayed when a submission exists but is not yet completed."},{"label":"W-4 Summary","value":"After completion, shows: Filing Status, Multiple Jobs (Yes/No), Exempt status (Yes/No). Does not show sensitive data like SSN or dollar amounts."},{"label":"I-9 Summary","value":"After completion, shows: Citizenship Status (U.S. Citizen, Noncitizen National, Lawful Permanent Resident, or Alien Authorized to Work) and document count. Includes a lock icon warning that I-9 forms cannot be changed after submission."},{"label":"State Withholding Summary","value":"After completion, shows: Filing Status, Allowances count, Additional Withholding dollar amount, and Exempt status (Yes/No)."},{"label":"Direct Deposit Summary","value":"After completion, shows: Bank name, Account Type, Routing number (last 4 digits, masked), Account number (last 4 digits, masked). Displayed in monospace font for masked values."},{"label":"Workers' Comp / Handbook Summary","value":"After completion, shows: 'Acknowledged on MM/dd/yyyy'. Simple confirmation with no additional field details."},{"label":"DocuSeal Signing Iframe","value":"Embedded iframe for the DocuSeal signing ceremony. Shown when a submission has a docuSealSubmitUrl and status is Pending or Opened. Allows camera and microphone access for identity verification. Sandboxed with allow-scripts, allow-same-origin, allow-forms, allow-popups."},{"label":"Pending Setup Banner","value":"Shown when a form template should have an electronic form definition (W-4, I-9, state withholding with sourceUrl) but the admin has not yet extracted it. Displays hourglass_empty icon with a message to contact the administrator."}]},{"heading":"Identity Documents (I-9)","items":[{"label":"List A Documents","value":"Documents that establish both identity AND employment authorization. Examples: U.S. Passport, Permanent Resident Card (Green Card), Employment Authorization Document (EAD), Foreign Passport with I-551 stamp. ONE List A document is sufficient."},{"label":"List B Documents","value":"Documents that establish identity only. Examples: Driver's License, State ID Card, School ID with photograph, Voter Registration Card, U.S. Military Card. Must be combined with a List C document."},{"label":"List C Documents","value":"Documents that establish employment authorization only. Examples: Social Security Card (unrestricted), Birth Certificate (U.S.), Certificate of Citizenship. Must be combined with a List B document."},{"label":"Document Upload","value":"Each list section has a file upload zone (app-file-upload-zone). Accepts PDF, JPG, JPEG, and PNG files up to 10 MB. Files are uploaded to the identity-docs entity type."},{"label":"Document Verification Status","value":"Each uploaded document shows either a verified badge with date (green verified icon + 'Verified MM/dd/yyyy') or a 'Pending verification' label. Verification is performed by an admin/manager reviewing the physical documents."},{"label":"Document Type","value":"The document type category (e.g., 'ListA', 'Passport', 'DriversLicense', 'SsnCard'). Displayed below the file name in the document list."},{"label":"Remove Document","value":"Red delete icon button on each document. Removes the identity document from the submission. Requires confirmation."},{"label":"Done Button","value":"Primary close button in the identity documents dialog footer. Closes the dialog and returns to the form detail view."},{"label":"Validation Rule","value":"I-9 requires either one List A document OR one List B + one List C document. The Submit Form button's validation popover will show the specific missing document requirement (e.g., 'List C document required' when only List B is uploaded)."}]},{"heading":"Validation Rules","items":[{"label":"Required Fields","value":"The server validates all fields marked required=true in the form definition JSON. Missing or empty required fields return a 400 error with the field label (e.g., 'First Name is required'). The client-side validation popover shows the same messages on hover over the disabled Submit button."},{"label":"SSN Format","value":"Social Security Number fields use a dedicated 'ssn' input type with automatic XXX-XX-XXXX formatting. Maximum length is 11 characters (9 digits + 2 dashes). The formatter inserts dashes as you type."},{"label":"Filing Status","value":"W-4 and state withholding forms require a filing status selection from radio button options. The field is required and must have a value selected before submission."},{"label":"Signature Fields","value":"Signature fields require typing your full legal name. The input has a distinctive signature-style appearance. A corresponding signature date field is rendered alongside and auto-populated."},{"label":"Identity Document Requirement (I-9)","value":"Before submitting an I-9, the system checks that identity documents are sufficient: either one List A document, or one List B + one List C document. If only List B is uploaded, the popover shows 'You need to upload a List C document'. If only List C, it shows 'You need to upload a List B document'. If neither, it shows 'Identity documents are required'."},{"label":"I-9 Section 2 Deadline","value":"Section 2 must be completed by the employer within 3 business days of the employee's first day of work. The deadline is stored as i9Section2OverdueAt and tracked for compliance."},{"label":"I-9 Reverification","value":"When work authorization documents have an expiration date, the system tracks i9ReverificationDueAt. HR is notified when reverification is approaching."},{"label":"Form Definition Version Pinning","value":"Each submission is pinned to the exact form definition version it was filled against (formDefinitionVersionId). This ensures the form can be regenerated with the original layout at any time, even if the form definition is later updated."},{"label":"BlocksJobAssignment","value":"Templates with blocksJobAssignment=true prevent the employee from being assigned to production jobs until the form is completed. This is enforced server-side — the job assignment API checks compliance status."},{"label":"Resubmission Restrictions","value":"I-9 forms cannot be resubmitted after completion (canResubmit returns false for formType 'i9'). All other form types allow the employee to update their submission by clicking the Update button."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Compliance Forms Knowledge Check",
            Slug = "compliance-forms-quiz",
            Summary = "Test your knowledge of the Compliance Forms module: form types, submission lifecycle, identity documents, validation rules, and payroll integration.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/account/tax-forms"]""",
            Tags = """["compliance","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"cf1","text":"You're a new employee and need to complete your tax withholding and employment eligibility forms. What is the recommended way to do this in QB Engineer?","options":[{"id":"a","text":"Navigate to Account > Tax Forms and fill out each form individually"},{"id":"b","text":"Use the unified onboarding wizard at /onboarding, which walks you through all required forms in a single guided workflow","isCorrect":true},{"id":"c","text":"Ask your manager to fill out the forms on your behalf in the Admin panel"},{"id":"d","text":"Download PDF forms from the IRS website, fill them out on paper, and scan them"}],"explanation":"The onboarding wizard at /onboarding guides new employees through all six form types (W-4, I-9, state withholding, direct deposit, workers' comp, handbook) in a single workflow. The Tax Forms page shows a banner linking to the wizard when forms are incomplete."},{"id":"cf2","text":"You completed your W-4 during onboarding but just got married. What should you do?","options":[{"id":"a","text":"Nothing — the W-4 is locked after initial submission"},{"id":"b","text":"Contact HR to delete your old W-4 so you can start over"},{"id":"c","text":"Go to Account > Tax Forms, click on the W-4 form, and click the Update button to resubmit with your new filing status","isCorrect":true},{"id":"d","text":"Submit a paper W-4 amendment form to the IRS directly"}],"explanation":"The W-4 can be updated at any time when your tax situation changes. Navigate to Account > Tax Forms, click the completed W-4 card, and click the Update button. This opens the form in edit mode so you can change your filing status and other withholding elections."},{"id":"cf3","text":"You completed your I-9 during onboarding but realize you made a typo in your name. What can you do?","options":[{"id":"a","text":"Go to Account > Tax Forms, click the I-9, and click Update to fix the typo"},{"id":"b","text":"Delete the I-9 submission and start over from the onboarding wizard"},{"id":"c","text":"Contact HR for corrections — I-9 forms cannot be changed after submission per federal regulations","isCorrect":true},{"id":"d","text":"Edit the signed PDF directly and re-upload it"}],"explanation":"I-9 forms cannot be changed after submission per federal law. The system enforces this by hiding the Update button for I-9 forms (canResubmit returns false). The completed I-9 detail shows a lock icon warning: 'I-9 forms cannot be changed after submission. Contact HR for corrections.'"},{"id":"cf4","text":"For the I-9 form, what identity documents are required?","options":[{"id":"a","text":"A driver's license and a Social Security card"},{"id":"b","text":"Either ONE List A document (identity + work authorization) OR ONE List B document (identity) PLUS ONE List C document (work authorization)","isCorrect":true},{"id":"c","text":"Any two forms of government-issued photo ID"},{"id":"d","text":"A passport is always required, no alternatives accepted"}],"explanation":"The I-9 requires either one List A document (which proves both identity and work authorization, such as a U.S. Passport) or a combination of one List B document (identity only, such as a Driver's License) plus one List C document (work authorization only, such as a Social Security Card)."},{"id":"cf5","text":"You uploaded a driver's license (List B) for your I-9 but the Submit button is still disabled. Why?","options":[{"id":"a","text":"The driver's license file format is not supported"},{"id":"b","text":"You also need a List C document (employment authorization) — List B alone is insufficient","isCorrect":true},{"id":"c","text":"The document has not been verified by an admin yet"},{"id":"d","text":"You need to upload at least three identity documents total"}],"explanation":"A driver's license is a List B document (identity only). You also need a List C document (employment authorization, such as a Social Security Card or Birth Certificate). The validation popover on the Submit button will show 'You need to upload a List C document' to guide you."},{"id":"cf6","text":"What happens after you submit your W-4 form data in the electronic form renderer?","options":[{"id":"a","text":"The form data is emailed to the IRS directly"},{"id":"b","text":"The system fills the official government PDF with your data and sends it to DocuSeal for your legally binding e-signature","isCorrect":true},{"id":"c","text":"A manager must manually approve the submission before it takes effect"},{"id":"d","text":"The data is saved but you must print and sign a paper copy separately"}],"explanation":"For forms with DocuSeal integration and AcroField mapping configured, submitting triggers the fill-and-sign flow: your form data fills the official government PDF using AcroForm field mapping, then DocuSeal handles the legally binding e-signature via an embedded iframe. The signed PDF is stored securely in MinIO."},{"id":"cf7","text":"A form card on the Tax Forms page shows an amber 'Required' badge. What does this mean?","options":[{"id":"a","text":"The form has a validation error that needs to be fixed"},{"id":"b","text":"The form has blocksJobAssignment enabled — you cannot be assigned to production jobs until it is completed","isCorrect":true},{"id":"c","text":"The form is past its annual renewal deadline"},{"id":"d","text":"An admin has flagged the form for immediate attention"}],"explanation":"The amber 'Required' badge appears on forms where blocksJobAssignment is true on the template. This means the employee cannot be assigned to production jobs on the Kanban board until the form is completed. This is enforced server-side by the job assignment API."},{"id":"cf8","text":"You're filling out the state withholding form. How does QB Engineer know which state form to show you?","options":[{"id":"a","text":"You manually select your state from a dropdown on the form"},{"id":"b","text":"It uses your home address from your employee profile"},{"id":"c","text":"It automatically determines the correct state form based on your assigned work location (CompanyLocation)","isCorrect":true},{"id":"d","text":"All employees fill out the same generic state form regardless of location"}],"explanation":"QB Engineer determines the state withholding form based on your work location (WorkLocationId on ApplicationUser, which maps to a CompanyLocation). The system calls getMyStateDefinition which resolves the state code, checks if the state has income tax, and returns the appropriate state-specific form definition."},{"id":"cf9","text":"You want to save your progress on a compliance form and finish it later. What should you do?","options":[{"id":"a","text":"Take a screenshot of the form and fill it out again later from scratch"},{"id":"b","text":"Click the Save Draft button — your form data is saved and you can return to continue where you left off","isCorrect":true},{"id":"c","text":"You cannot save progress — the form must be completed in one sitting"},{"id":"d","text":"Close the browser tab — the form auto-saves every keystroke"}],"explanation":"The Save Draft button (save icon) in the form renderer footer saves your current form data without submitting. When you return to the form later, your saved draft data is loaded automatically so you can continue where you left off."},{"id":"cf10","text":"What is the difference between 'Pending' and 'Opened' submission statuses?","options":[{"id":"a","text":"Pending means the form has not been started; Opened means the employee is currently filling it out"},{"id":"b","text":"Pending means the submission was created but the DocuSeal signing link has not been opened yet; Opened means the signing link has been accessed","isCorrect":true},{"id":"c","text":"Pending means awaiting manager approval; Opened means the manager has reviewed it"},{"id":"d","text":"There is no difference — they are interchangeable statuses"}],"explanation":"Pending indicates a submission has been created (form data may be saved) but the DocuSeal signing ceremony has not been accessed. Opened indicates the employee has clicked the DocuSeal signing link and the signing iframe has been loaded. Both are intermediate states before Completed."},{"id":"cf11","text":"An employer (manager/admin) needs to complete Section 2 of an employee's I-9. What is the deadline?","options":[{"id":"a","text":"Within 24 hours of the employee's hire date"},{"id":"b","text":"Within 3 business days of the employee's first day of work","isCorrect":true},{"id":"c","text":"Within 30 calendar days of the employee's start date"},{"id":"d","text":"There is no deadline — it can be completed at any time"}],"explanation":"Per federal regulations, I-9 Section 2 must be completed within 3 business days of the employee's first day of work. QB Engineer tracks this as the i9Section2OverdueAt field, which is set when Section 1 is signed. The system enforces that Section 1 must be completed before Section 2 can begin."},{"id":"cf12","text":"You live in Texas and are asked to complete state withholding. What happens?","options":[{"id":"a","text":"You fill out the standard Texas withholding form"},{"id":"b","text":"The system shows that Texas has no state income tax and no form is required","isCorrect":true},{"id":"c","text":"You must fill out the federal W-4 again as a substitute"},{"id":"d","text":"An error is displayed because Texas is not a supported state"}],"explanation":"Texas is one of several states (along with Florida, Nevada, etc.) that have no state income tax. The state withholding system categorizes these as 'no_tax' states. The employee is informed that no state withholding form is required for their work location."},{"id":"cf13","text":"After completing a W-4, what information is shown in the submission summary card?","options":[{"id":"a","text":"Your full Social Security Number, exact withholding dollar amounts, and employer EIN"},{"id":"b","text":"Filing Status, Multiple Jobs (Yes/No), and Exempt status — no sensitive data like SSN or dollar amounts","isCorrect":true},{"id":"c","text":"Nothing — the summary is blank for security reasons"},{"id":"d","text":"A link to download the raw form data JSON"}],"explanation":"The W-4 summary shows only non-sensitive fields: Filing Status, whether Multiple Jobs was selected (Yes/No), and Exempt status (Yes/No). Sensitive data like SSN and dollar amounts are not displayed back to the user. The W-4 is classified as a sensitive form (isSensitive = true), so even when resubmitting, previous data is not pre-filled."},{"id":"cf14","text":"What does 'form definition version pinning' mean for compliance form submissions?","options":[{"id":"a","text":"The form is locked to a specific CSS theme version"},{"id":"b","text":"Each submission records the exact form definition version it was filled against, so the form can be regenerated with the original layout even if the definition is later updated","isCorrect":true},{"id":"c","text":"The form can only be submitted once per calendar year"},{"id":"d","text":"The employer must approve the form version before it can be used"}],"explanation":"Each submission stores a formDefinitionVersionId that pins it to the exact form layout used when filling it out. This is important for compliance: if the IRS releases a new W-4 revision, previously submitted forms can still be viewed and regenerated using their original layout. The FormDefinitionVersion entity tracks template ID, state code, effective date, and the full form definition JSON."},{"id":"cf15","text":"How do you download a signed copy of a completed compliance form?","options":[{"id":"a","text":"Go to Account > Tax Forms, click the completed form, and click the Download button (download icon)","isCorrect":true},{"id":"b","text":"Contact HR to email you a copy"},{"id":"c","text":"Navigate to the Files section and search for compliance documents"},{"id":"d","text":"Signed PDFs are not available for download — only viewable in the browser"}],"explanation":"On the completed form's detail page, click the Download button (download icon) to download the signed PDF. The system retrieves the file from MinIO storage and triggers a browser download with the form name as the filename (e.g., 'W-4 Employee\\'s Withholding Certificate.pdf'). The button shows a spinning sync icon while the download is in progress."}]}"""
        });

        // ── Admin: Form Templates (Article) ──────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Compliance Forms for Administrators",
            Slug = "compliance-admin-templates",
            Summary = "How administrators manage compliance form templates from Admin > Compliance: create/edit/delete custom templates, set the flags that control behavior (requires identity docs, blocks job assignment, auto-sync), extract an electronic form definition from a government PDF, and resolve the 'pending setup' state.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 7,
            IsPublished = true,
            SortOrder = 5,
            AppRoutes = """["/admin/compliance"]""",
            Tags = """["compliance","admin","templates","configuration"]""",
            ContentJson = """{"body":"## Compliance Forms for Administrators\n\nAdministrators configure which compliance forms an employee must complete, how each form behaves, and how the system renders it electronically. This all lives on the **Compliance** tab of the Admin area (Admin > Compliance), which opens the form-templates panel. This tab is the default landing tab for Managers and Office Managers who don't have the broader Admin tabs.\n\n> Access: template create/edit/delete is **Admin-only**. The capability gate is **CAP-QC-COMPLIANCE-FORMS** — if compliance forms are disabled for your install, the whole tab is hidden.\n\n### The Templates Panel\n\nThe panel header shows the template count plus two actions: **Sync All** (re-pulls the source PDF for every auto-sync template) and **New Template** (the green create button). Below that is a data table of every template with these columns:\n\n- **Icon** — the Material icon shown to employees on their Tax Forms list.\n- **Name** — the official form name. If a template still needs an electronic form definition, a yellow **No form definition** chip appears next to the name.\n- **Type** — the form type: W-4, I-9, State Withholding, Direct Deposit, Workers' Comp, or Handbook.\n- **Auto** / **Manual** chip — whether the template auto-syncs from a source URL.\n- **Last Synced** — the last successful source pull, or *Never*.\n- **Active** / **Inactive** — whether employees see the form.\n- **Actions** — row-level icon buttons (see below).\n\n### System Templates vs Custom Templates\n\nThe six built-in form types (W-4, I-9, State Withholding, Direct Deposit, Workers' Comp, Handbook) ship as **system templates**. System templates cannot be deleted, and clicking their row-action edit button opens an **upload-only** dialog (the icon is `upload_file`, not `edit`) — you can attach a manual document override and configure PDF fill, but you can't rename the form or change its core identity. Custom templates you create yourself have a full edit dialog and can be deleted.\n\n### Creating a Custom Template\n\nClick **New Template** to open the create dialog. The fields are:\n\n- **Name** (required) — the form's display name.\n- **Form Type** (required) — one of the six types. This drives the summary card, identity-doc behavior, and resubmission rules.\n- **Description** — shown under the name on the employee's card.\n- **Icon** (required) — a Material icon name (e.g., `description`, `badge`).\n- **Profile Completion Key** (required) — the profile key this form satisfies. When the employee completes the form, this key flips to done, which is what onboarding-progress and job-assignment gating read.\n- **Source URL** — the URL of the official government PDF. Required if you want the system to extract an electronic form definition or auto-sync.\n- **Sort Order** — position in the employee's form list.\n- **Toggles**: **Auto-sync from source** (re-pull the PDF on a schedule), **Active** (visible to employees), **Requires Identity Docs** (turns on the List A / List B / List C upload dialog — used by I-9), and **Blocks Job Assignment** (an incomplete form prevents the employee from being assigned to production jobs and shows a red *Required* badge).\n\nClick **Create** to save. The validation button surfaces any missing required fields.\n\n### Editing a Template\n\nFor a custom template, the edit dialog has the same fields plus an **AcroField Map** JSON textarea. The AcroField map tells the PDF-fill engine which collected field maps to which named field in the official government PDF's form (its AcroForm). This is what lets the system pre-fill the real W-4 or I-9 PDF before sending it to DocuSeal for signature.\n\n### Extracting an Electronic Form Definition\n\nW-4, I-9, and State Withholding forms are rendered electronically — the employee fills the actual government layout, not a simplified approximation. That layout is a **form definition** the system generates from the official PDF:\n\n1. Set a **Source URL** (or upload a manual document override) on the template.\n2. In the template row's actions, click the **Extract definition** button (the `auto_fix_high` wand icon). It appears only when the template has no current form definition AND has a source URL or an uploaded override.\n3. The pipeline runs pdf.js extraction → smart layout parsing → AI verification/refinement, producing a JSON form definition (step sections, filing-status radio groups, amount lines, signature blocks, worksheets).\n4. When extraction finishes, the **No form definition** chip disappears and employees can fill the form.\n\n### The 'Pending Setup' State\n\nUntil a template that should have an electronic definition (W-4 / I-9 / State Withholding, or any template with a source URL) has been extracted, it sits in a *pending setup* state. The template row shows the yellow **No form definition** chip, and any employee who opens that form sees a *pending setup* banner (an hourglass icon with a message to contact the administrator) instead of a fillable form. Resolve it by running Extract definition. Until then, employees cannot complete the form.\n\n### Configuring PDF Fill (system templates)\n\nFor system templates, the upload dialog also exposes a **PDF fill configuration** section: upload a blank fillable PDF (the `filledPdfTemplateId`) and provide the **AcroField Map** JSON. Together these let the system fill the official PDF with collected data before the DocuSeal signing ceremony. A green chip confirms when a blank PDF is linked.\n\n### Syncing\n\n**Sync All** in the header re-pulls every auto-sync template's source. A row-level **Sync** button (the `sync` icon) appears on individual templates that are auto-sync and have a source URL, letting you refresh just one. The *Last Synced* column shows when each template was last pulled.\n\n### What Administrators Cannot Do\n\nAdmins configure templates and can run the employer side of compliance (see *Managing Employee Compliance* and *Completing I-9 Section 2*). They do **not** fill out an employee's W-4/I-9 personal data — employees complete their own forms through the onboarding wizard or their Tax Forms page. Admins also cannot edit a submitted I-9 (federal law); corrections require a new submission per USCIS rules.","sections":[]}"""
        });

        // ── Admin: State Withholding Configuration (Article) ─────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "State Withholding Configuration",
            Slug = "compliance-state-withholding",
            Summary = "How administrators use the State Withholding configuration dialog (Admin > Compliance) to see which states are ready for e-sign, which need a PDF uploaded, which accept the federal W-4, and which have no income tax — and how an employee's work location decides which form they get.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 6,
            AppRoutes = """["/admin/compliance"]""",
            Tags = """["compliance","admin","state-withholding","tax"]""",
            ContentJson = """{"body":"## State Withholding Configuration\n\nState income-tax withholding is more complicated than a single form: every state handles it differently. Some have their own withholding certificate, some just use the federal W-4, and some have no income tax at all. QB Engineer's **State Withholding configuration dialog** gives administrators a single board to see and manage the readiness of all states.\n\n> Access this from Admin > Compliance: on the form-templates table, the **State Withholding** row has an `open_in_new` action button that opens the configuration dialog.\n\n### How a State Form Gets Picked for an Employee\n\nThis is the key mental model. An employee never picks their state from a dropdown. Instead, the system resolves the correct state withholding form from the employee's **assigned work location** (the `WorkLocationId` on their user record, which points at a CompanyLocation; a null work location falls back to the install's default location). The location's state determines which of the four buckets below applies.\n\n### The Four State Buckets\n\nThe dialog opens with a summary strip of four counts, then lists every state grouped into four categories:\n\n1. **Ready for e-sign** (`verified` icon) — states that have their own withholding form AND already have an extracted electronic form definition. Employees in these states get a fully electronic fill-and-sign experience. Examples include states like California and New York once their forms are set up.\n\n2. **Needs PDF upload** (`upload_file` icon) — states that have their own withholding form but **don't yet have an electronic definition**. Employees in these states can't complete the form until an admin uploads the state's PDF and extracts a definition. These cards are styled as pending. This bucket is your to-do list: it tells you exactly which state forms still need setup work.\n\n3. **Accept federal W-4** (`description` icon) — states that don't publish their own certificate and instead use the federal W-4 as the basis for state withholding. Employees in these states don't fill a separate state form; their federal W-4 elections carry over.\n\n4. **No state income tax** (`block` icon) — states with no income tax (Texas, Florida, Nevada, Washington, etc.). Employees in these states see a message that no state withholding form is required, and complete nothing.\n\n### Reading and Selecting a State Card\n\nEach state card shows the **state code** (e.g., TX), the **state name**, the **form name** where applicable, and a **status chip** with an icon. The card for the employee's currently-resolved state is highlighted as active. Clicking a card selects that state — used when you're configuring or reviewing a specific state's setup. Cards are disabled while a save is in progress.\n\n### Typical Admin Workflow\n\n1. Open the dialog and look at the **Needs PDF upload** count. If it's zero, every state with its own form is ready.\n2. For each state in that bucket, obtain the official state withholding PDF, attach it (as a manual override or source URL on the corresponding template), and run **Extract definition** (see *Compliance Forms for Administrators*).\n3. Once extracted, the state moves to **Ready for e-sign** and employees at locations in that state can complete the form electronically.\n4. States in the **Accept federal W-4** and **No state income tax** buckets need no action — they're informational and resolve automatically.\n\n### Why This Matters\n\nIf an employee's work location is in a state that's stuck in **Needs PDF upload**, that employee will hit a *pending setup* state on their state withholding form and can't finish onboarding's tax step. Keeping the Needs-PDF-upload bucket empty for the states you actually employ people in is the practical goal — you don't need every U.S. state set up, only the ones your CompanyLocations cover.","sections":[]}"""
        });

        // ── Admin/Manager: Managing Employee Compliance (Article) ────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Managing Employee Compliance",
            Slug = "compliance-managing-employees",
            Summary = "The employer-side workflow on Admin > Compliance: pick an employee, review their per-employee compliance panel (form submissions with statuses and I-9 sub-states, identity documents, pay stubs, tax docs), verify uploaded identity documents, download signed PDFs, and send a compliance reminder.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 7,
            IsPublished = true,
            SortOrder = 7,
            AppRoutes = """["/admin/compliance"]""",
            Tags = """["compliance","admin","manager","i-9","identity-documents"]""",
            ContentJson = """{"body":"## Managing Employee Compliance\n\nBeyond configuring templates, administrators, managers, and office managers handle the employer side of compliance: confirming employees have completed their forms, verifying the identity documents they uploaded, downloading signed PDFs for the file, and nudging people who are behind.\n\n> Access: the per-employee review actions (view detail, verify documents, send reminder, complete I-9 Section 2) are open to **Admin, Manager, and Office Manager** roles — not just full admins. The Users table on the Admin overview also shows a per-user compliance progress chip (e.g., 6/8) so you can spot who's incomplete at a glance.\n\n### Opening an Employee's Compliance Panel\n\nFrom Admin > Compliance, choose an employee. The per-employee compliance panel loads their full compliance picture. If no employee is selected, the panel shows a *select an employee* empty state.\n\nThe panel header shows the employee's name and email, and a **Send Reminder** button (a `notifications_active` bell). Below the header, a **state withholding banner** summarizes how that employee's state is handled — no state tax, uses federal W-4, or a named state form — and shows the resolution source (their work location).\n\n### Form Submissions Table\n\nThe **Form Submissions** section lists every compliance form for the employee with:\n\n- **Form** — the template name.\n- **Status** — the submission status (Pending, Opened, Completed, Expired, Declined).\n- **I-9 sub-state chip** — for I-9 rows only, an extra chip shows the two-section state of the I-9 (Section 1 done by the employee, Section 2 done by the employer). This is how you tell at a glance whether you still owe Section 2.\n- **Signed** — the signed date, or an em dash if not signed.\n- **Actions** — a **Download** button (appears once a signed PDF exists) to pull the signed PDF for your records, and — for an I-9 where the employee has signed Section 1 but Section 2 isn't done yet — a **Complete Section 2** action (`how_to_reg` icon). See *Completing I-9 Section 2* for that flow.\n\n### Identity Documents Table\n\nThe **Identity Documents** section lists the List A / List B / List C documents the employee uploaded for their I-9, with:\n\n- **Type** — the document type/category.\n- **File** — the uploaded file name.\n- **Uploaded** — the upload date.\n- **Verified** — a green *Verified* chip once an admin/manager has confirmed it against the physical document, or a yellow *Pending* chip until then.\n- **Actions** — for unverified documents, a **Verify** button (the `verified` checkmark). Click it to mark the document verified after you've physically inspected it. This is a deliberate human step: the system stores and displays the upload, but a person must confirm it's genuine.\n\nIf the employee has no submissions or no identity documents yet, each section shows its own empty state.\n\n### Pay Stubs and Tax Documents\n\nThe same panel also surfaces the employee's **pay stubs** and **tax documents** (W-2 / 1099, etc.), each in its own table with download actions, and upload zones for adding manual records. Records sourced from a connected accounting provider show a *Synced* chip; manually-uploaded ones show *Manual* and can be deleted. (These overlap with the Payroll feature — covered there in depth.)\n\n### Sending a Compliance Reminder\n\nWhen an employee is behind on required forms, click **Send Reminder** in the panel header. This dispatches a notification prompting them to finish their outstanding compliance forms. Use it instead of chasing people manually — it's logged and routes through the normal notification system.\n\n### What You're Confirming\n\nThe employer-side job is verification and record-keeping, not data entry: confirm each required form reached **Completed**, confirm identity documents are **Verified**, complete **I-9 Section 2** within the deadline, and keep signed PDFs on file. You never edit the employee's personal entries on a W-4 or I-9 — those belong to the employee, and a submitted I-9 is immutable per federal law.","sections":[]}"""
        });

        // ── Admin/Manager: Completing I-9 Section 2 (Article) ────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Completing I-9 Section 2",
            Slug = "compliance-i9-section2",
            Summary = "The employer's responsibility on the I-9: after the employee signs Section 1, an Admin/Manager/Office Manager completes Section 2 within 3 business days by recording the inspected identity documents (List A, or List B + List C) and any work-authorization expiration for reverification.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 8,
            AppRoutes = """["/admin/compliance"]""",
            Tags = """["compliance","i-9","section-2","admin","manager"]""",
            ContentJson = """{"body":"## Completing I-9 Section 2\n\nThe I-9 is a two-part form by design. **Section 1** is the employee's attestation of identity and work authorization — they complete and sign it themselves. **Section 2** is the **employer's** responsibility: a company representative physically examines the employee's identity documents and records what they saw. QB Engineer routes Section 2 to Admins, Managers, and Office Managers.\n\n> The hard rule: **Section 2 must be completed within 3 business days of the employee's first day of work.** The system stamps an overdue deadline (`i9Section2OverdueAt`) when Section 1 is signed, and tracks it for compliance. Section 1 must be signed before Section 2 can begin.\n\n### Where to Start It\n\nOpen the employee's compliance panel (Admin > Compliance, then select the employee — see *Managing Employee Compliance*). In the **Form Submissions** table, an I-9 row that has Section 1 signed but Section 2 outstanding shows a **Complete Section 2** action (the `how_to_reg` icon). Click it to open the Complete I-9 Section 2 dialog.\n\n### What the Dialog Asks For\n\n**Document List Type** (required) — choose how the employee proved identity and work authorization:\n\n- **List A** — a single document that establishes **both** identity and employment authorization (e.g., U.S. Passport, Permanent Resident Card, Employment Authorization Document). One List A document is sufficient.\n- **List B + C** — a **List B** document for identity (e.g., Driver's License, State ID) **plus** a **List C** document for employment authorization (e.g., Social Security Card, Birth Certificate). You need one of each.\n\n**First Day of Employment** (required) — the employee's start date, which anchors the 3-business-day deadline.\n\nDepending on your List Type choice, the dialog reveals document fields:\n\n- For **List A**: document type, document number, issuing authority, and expiration date — for the single List A document you inspected.\n- For **List B + C**: the same four fields for the **List B** document, then again for the **List C** document.\n\nRecord exactly what's on the physical document you examined. You're certifying that the documents appear genuine and relate to the employee.\n\n### Reverification\n\nAt the bottom, the **Work Authorization Expiration** date field captures when the employee's work authorization expires, if applicable. When set, the system schedules a **reverification** reminder (`i9ReverificationDueAt`) so HR is prompted before the authorization lapses. Leave it blank for documents that don't expire (e.g., a U.S. Passport for a citizen).\n\n### Saving\n\nClick **Complete Section 2** (`how_to_reg`). The validation button surfaces any missing required fields. On save, the I-9's employer section is recorded and the submission's I-9 sub-state advances — the *Complete Section 2* action disappears from the row and the I-9 reads as fully done.\n\n### What You Cannot Do Afterward\n\nLike the rest of the I-9, a completed Section 2 is part of an immutable federal record. The employee can't edit their submitted I-9, and corrections to a completed I-9 follow USCIS correction rules rather than an in-app edit. If you realize you recorded the wrong document, follow your organization's I-9 correction procedure — don't try to delete and re-create the record.\n\n### Why the 3-Day Deadline Is Strict\n\nThe 3-business-day window is a federal requirement, not a soft target. Missing it is an I-9 compliance violation. The overdue tracking exists so the deadline is visible and actionable — make completing Section 2 part of every new hire's first week, right alongside getting them their equipment.","sections":[]}"""
        });

