            ContentJson = """{"title":"Compliance Admin Field Reference","groups":[{"heading":"Access & Location","items":[{"label":"Where","value":"Admin > Compliance tab opens the form-templates panel. It is the default landing tab for Manager and Office Manager roles."},{"label":"Capability","value":"CAP-QC-COMPLIANCE-FORMS. If disabled for the install, the entire compliance area is hidden."},{"label":"Template CRUD roles","value":"Create / edit / delete templates is Admin-only."},{"label":"Employer-review roles","value":"View per-employee compliance, verify identity docs, send reminders, and complete I-9 Section 2 are open to Admin, Manager, and Office Manager."}]},{"heading":"Templates Panel","items":[{"label":"Sync All","value":"Header button that re-pulls the source PDF for every auto-sync template."},{"label":"New Template","value":"Green create button. Opens the template create dialog (custom templates only)."},{"label":"No form definition chip","value":"Yellow chip next to a template name when the template needs an electronic definition (W-4/I-9/State Withholding, or any template with a source URL) but hasn't been extracted yet."},{"label":"Auto / Manual chip","value":"Whether the template auto-syncs from its source URL."},{"label":"Last Synced","value":"Date of the last successful source pull, or Never."},{"label":"Active / Inactive","value":"Whether employees see the form in their Tax Forms list."},{"label":"System template","value":"The six built-in types (W-4, I-9, State Withholding, Direct Deposit, Workers' Comp, Handbook). Cannot be deleted; their edit action is upload-only (upload_file icon)."},{"label":"Custom template","value":"A template you created. Full edit dialog; can be deleted (delete icon)."}]},{"heading":"Template Create/Edit Fields","items":[{"label":"Name (required)","value":"The form's display name."},{"label":"Form Type (required)","value":"W-4, I-9, State Withholding, Direct Deposit, Workers' Comp, or Handbook."},{"label":"Description","value":"Shown under the name on the employee's form card."},{"label":"Icon (required)","value":"Material icon name (e.g., description, badge)."},{"label":"Profile Completion Key (required)","value":"The profile key the form satisfies; drives onboarding progress and job-assignment gating."},{"label":"Source URL","value":"URL of the official government PDF. Needed to extract a definition or auto-sync."},{"label":"Sort Order","value":"Position of the form in the employee's list."},{"label":"Auto-sync from source","value":"Toggle: re-pull the source PDF on a schedule."},{"label":"Active","value":"Toggle: visible to employees."},{"label":"Requires Identity Docs","value":"Toggle: turns on the List A / B / C upload dialog (used by I-9)."},{"label":"Blocks Job Assignment","value":"Toggle: an incomplete form blocks production-job assignment and shows a red Required badge to the employee."},{"label":"AcroField Map (edit only)","value":"JSON mapping collected fields to the official PDF's AcroForm field names; powers PDF pre-fill before DocuSeal signing."}]},{"heading":"Extract / Sync / Pending Setup","items":[{"label":"Extract definition","value":"Wand icon (auto_fix_high) row action. Visible only when the template has no current definition AND has a source URL or uploaded override. Runs pdf.js extraction + AI verification to build the electronic form layout."},{"label":"Pending setup state","value":"A template needing an electronic definition that hasn't been extracted. Shows the No-form-definition chip; employees see an hourglass pending-setup banner and cannot fill the form. Resolve with Extract definition."},{"label":"Row Sync","value":"sync icon row action. Appears on auto-sync templates with a source URL; refreshes just that template."},{"label":"Blank PDF + PDF fill (system templates)","value":"In the upload dialog: link a blank fillable PDF (filledPdfTemplateId) and provide the AcroField Map so the official PDF can be pre-filled before signing. Green chip confirms the blank PDF is linked."}]},{"heading":"State Withholding Dialog","items":[{"label":"How to open","value":"On the templates table, the State Withholding row's open_in_new action opens the configuration dialog."},{"label":"Ready for e-sign","value":"States with their own form AND an extracted definition. Employees get a fully electronic experience."},{"label":"Needs PDF upload","value":"States with their own form but no definition yet. Employees there hit pending-setup until an admin uploads the PDF and extracts. This is the admin to-do bucket."},{"label":"Accept federal W-4","value":"States that use the federal W-4 as the withholding basis; no separate state form."},{"label":"No state income tax","value":"States with no income tax (TX, FL, NV, etc.); employees complete nothing."},{"label":"State resolution","value":"An employee's state form is chosen from their work location (WorkLocationId / CompanyLocation), not a dropdown. Null work location uses the default location."},{"label":"State card","value":"Shows state code, name, form name (where applicable), and a status chip. The employee's resolved state is highlighted active. Clicking selects the state."}]},{"heading":"Per-Employee Review","items":[{"label":"Send Reminder","value":"Bell button (notifications_active) in the panel header. Notifies the employee to finish outstanding compliance forms."},{"label":"State withholding banner","value":"Summarizes the employee's state handling (no tax / federal W-4 / named state form) and the resolution source."},{"label":"Submission status","value":"Pending, Opened, Completed, Expired, or Declined for each form."},{"label":"I-9 sub-state chip","value":"On I-9 rows, shows whether Section 1 (employee) and Section 2 (employer) are done."},{"label":"Download signed PDF","value":"Download icon on submissions that have a signed PDF; pulls the signed document for your records."},{"label":"Verify identity document","value":"verified checkmark action on an unverified identity document. Marks it verified after you physically inspect it. Until then it shows a Pending chip."}]},{"heading":"Complete I-9 Section 2","items":[{"label":"Who & deadline","value":"Admin/Manager/Office Manager completes Section 2 within 3 business days of the employee's first day. Section 1 must be signed first."},{"label":"Entry point","value":"Complete Section 2 action (how_to_reg icon) on an I-9 row where Section 1 is signed but Section 2 is not."},{"label":"Document List Type (required)","value":"List A (one document proving identity + work authorization) OR List B+C (List B identity document + List C work-authorization document)."},{"label":"First Day of Employment (required)","value":"Anchors the 3-business-day deadline."},{"label":"Per-document fields","value":"Document type, number, issuing authority, expiration date — for the List A document, or for each of the List B and List C documents."},{"label":"Work Authorization Expiration","value":"Optional date that schedules an I-9 reverification reminder before authorization lapses. Leave blank for non-expiring documents."},{"label":"Immutability","value":"A completed I-9 (including Section 2) is an immutable federal record; corrections follow USCIS rules, not an in-app edit."}]}]}"""
